        ```code
        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Comparator;

public class Crypto {
	static class Calculator {
		int monede;
		int pretUpgrade;

		Calculator() {
			this.monede = 0;
			this.pretUpgrade = 0;
		}

	}

	static class Task {
		public static final String INPUT_FILE = "crypto.in";
		public static final String OUTPUT_FILE = "crypto.out";

		public static int total;

		int n;
		Calculator[] c;

		public void solve() {
			readInput();
			writeOutput(getResult());
		}

		private void readInput() {
			try {
				BufferedReader br = new BufferedReader(new FileReader(INPUT_FILE));
				String line = br.readLine();
				String[] tokens = line.trim().split("\\s+");
				n = Integer.parseInt(tokens[0]);
				total = Integer.parseInt(tokens[1]);
				c = new Calculator[n];
				for (int i = 0; i < n; i++) {
					line = br.readLine();
					tokens = line.trim().split("\\s+");
					c[i] = new Calculator();
					c[i].monede = Integer.parseInt(tokens[0]);
					c[i].pretUpgrade = Integer.parseInt(tokens[1]);
				}
				br.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}

		}

		private int getResult() {
			Arrays.sort(c, new Comparator<Calculator>() {
				/// sortez vectorul de Actiuni crescator dupa moneda
				public int compare(Calculator a, Calculator b) {
					if (a.monede == b.monede) {
						return 0;
					}
					if (a.monede > b.monede) {
						return 1;
					}
					return -1;
				}
			});

			int sumaMax = 0;
			int minimMoneda = c[0].monede;
			/// initial poate sa mineze prima valoare din vectorul sortat / ora

			for (int i = 0; i < c.length - 1 ; i++) {
				/// suma pentru a upgrade o data monedele de la 0 -> i
				sumaMax += c[i].pretUpgrade;

				/// daca se intalneste o valoare mai mare se incearca upgrade
				if (c[i].monede < c[i + 1].monede) {

					/// de cate ori putem face upgrade maxim cu suma pe care o avem
					int diff = total / sumaMax;

					/// de cate ori este nevoie pentru a egala
					/// se alege minimul dintre cele 2 optiuni
					if (c[i + 1].monede - c[i].monede  < diff) {
						diff = c[i + 1].monede - c[i].monede;
					}

					/// daca nu se mai poate face upgrade STOP
					if (diff == 0) {
						break;
					}
					/// daca se poate face upgrade actualizeza bugetul si minimul
					if (total >= sumaMax * diff) {
						total = total - sumaMax * diff;
						minimMoneda = c[i].monede + diff;
					}
				}
			}

			/// se incearca upgrade pe toate moonedele daca bugetul permite
			sumaMax += c[c.length - 1].pretUpgrade;
			int upgradeTotal = total / sumaMax;
			minimMoneda += upgradeTotal;

			return minimMoneda;
		}

		private void writeOutput(int result) {
			try {
				PrintWriter pw = new PrintWriter(new File(OUTPUT_FILE));
				pw.printf("%d\n", result);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}


        ```

