        #include <algorithm>
#include <cstdio>
#include <deque>

#define MAXN 1005
#define INF 2000000000

using namespace std;

int N, M, xs, ys, xf, yf;
int dx[4] = {1, 0, -1, 0};
int dy[4] = {0, 1, 0, -1};

char mat[MAXN][MAXN];

int dist[MAXN][MAXN][4];

struct coord {
    int x, y, dir;
};

bool is_inside(coord node) {
    return node.x >= 1 && node.x <= N && node.y >= 1 && node.y <= M;
}

int main() {
    freopen("beamdrone.in", "r", stdin);
    freopen("beamdrone.out", "w", stdout);

    scanf("%d %d %d %d %d %d", &N, &M, &xs, &ys, &xf, &yf);
    xs++;
    ys++;
    xf++;
    yf++;

    for (int i = 1; i <= N; i++) {
        scanf(" %s", mat[i] + 1);
        for (int j = 1; j <= M; j++) {
            if (mat[i][j] == 'W') {
                mat[i][j] = 1;
            } else {
                mat[i][j] = 0;
            }
        }
    }

    deque<coord> q;
    coord node;
    node.x = xs;
    node.y = ys;

    node.dir = 0;
    q.push_back(node);
    node.dir = 1;
    q.push_back(node);
    node.dir = 2;
    q.push_back(node);
    node.dir = 3;
    q.push_back(node);

    for (int i = 1; i <= N; i++) {
        for (int j = 1; j <= M; j++) {
            for (int k = 0; k < 4; k++) {
                dist[i][j][k] = INF;
            }
        }
    }
    dist[xs][ys][0] = dist[xs][ys][1] = dist[xs][ys][2] = dist[xs][ys][3] = 0;

    while (!q.empty()) {
        node = q.front();
        q.pop_front();

        for (int dir = 0; dir < 4; dir++) {
            coord son;
            son.x = node.x + dx[dir];
            son.y = node.y + dy[dir];
            son.dir = dir;

            if (is_inside(son) && !mat[son.x][son.y] &&
                dist[son.x][son.y][son.dir] >
                    dist[node.x][node.y][node.dir] + (son.dir != node.dir)) {
                dist[son.x][son.y][son.dir] =
                    dist[node.x][node.y][node.dir] + (son.dir != node.dir);
                if (son.dir == node.dir) {
                    q.push_front(son);
                } else {
                    q.push_back(son);
                }
            }
        }
    }

    printf("%d\n", min(min(dist[xf][yf][0], dist[xf][yf][1]),
                       min(dist[xf][yf][2], dist[xf][yf][3])));
    return 0;
}


