        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Stack;
import java.util.StringTokenizer;

public class Ferate {
	static class Task {
		public static final String INPUT_FILE = "ferate.in";
		public static final String OUTPUT_FILE = "ferate.out";

		// numarul maxim de noduri
		public static final int NMAX = (int) 1e5 + 5; // 10^5 + 5 = 100.005

		// n = numar de noduri, m = numar de muchii/arce, s = nodul sursa
		int n, m, s;

		// my_scc[i] = the strongly connected component which contains node i
		int[] my_scc;

		int sccs;

		// adj[node] = lista de adiacenta a nodului node
		// exemplu: daca adj[node] = {..., neigh, ...} => exista arcul (node, neigh)
		@SuppressWarnings("unchecked")
		ArrayList<Integer>[] adj = new ArrayList[NMAX];

		// parent[node] = parent of node in the DFS traversal
		int[] parent;

		// found[node] = the timestamp when node was found (when started to visit its subtree)
		// Note: The global timestamp is incremented everytime a node is found.
		int[] found;

		// the minimum accessible timestamp that node can see/access
		// low_link[node] = 
		// min { found[x] | x is node OR x in ancestors(node) OR x in descendants(node) };
		int[] low_link;

		// visiting stack: nodes are pushed into the stack in visiting order
		Stack<Integer> nodes_stack = new Stack<>();

		// in_stack[node] = true, if node is in stack
		//                  false, otherwise
		boolean[] in_stack;

		// global timestamp
		int timestamp;

		public void solve() {
			readInput();
			writeOutput(getResult());
		}

		private void readInput() {
			try {
				BufferedReader br = new BufferedReader(new FileReader(INPUT_FILE));
				StringTokenizer st = new StringTokenizer(br.readLine());

				n = Integer.parseInt(st.nextToken());
				m = Integer.parseInt(st.nextToken());
				s = Integer.parseInt(st.nextToken());

				for (int i = 1; i <= n; i++) {
					adj[i] = new ArrayList<>();
				}
				for (int i = 1; i <= m; i++) {
					int x, y;
					st = new StringTokenizer(br.readLine());
					x = Integer.parseInt(st.nextToken());
					y = Integer.parseInt(st.nextToken());
					adj[x].add(y); // arc (x, y)
				}
				br.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(int k) {
			try {
				BufferedWriter writer = new BufferedWriter(new FileWriter(OUTPUT_FILE));
				writer.write(Integer.toString(k) + "\n");
				writer.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private int getResult() {
			tarjan_scc();


			// initial toate componentele au nevoie de o muchie spre ele, 
			// mai putin cea in care se afla sursa.
			boolean[] needs_edge = new boolean[n + 1];
			for (int i = 0 ; i < sccs; i++) {
				if (my_scc[s] == i) {
					needs_edge[i] = false;
				} else {
					needs_edge[i] = true;
				}
			}

			// pentru fiecare muchie intre 2 componente diferite, componenta nodului destinatie
			// nu mai are nevoie de adaugarea unei noi muchii.
			for (int node = 1; node <= n; node ++) {
				for (Integer neigh : adj[node]) {
					if (my_scc[node] != my_scc[neigh]) {
						needs_edge[my_scc[neigh]] =  false;
					}
				}
			}

			int k = 0;

			// numar cate componente tare conexe mai au nevoie de muchii de la nodul sursa spre ele.
			for (int i = 0 ; i < sccs; i++) {
				if (needs_edge[i]) {
					k++;
				}
			}

			return k;

		}

		private void tarjan_scc() {
			// STEP 1: initialize results
			parent = new int[n + 1];
			found = new int[n + 1];
			low_link = new int[n + 1];
			in_stack = new boolean[n + 1];
			my_scc = new int[n + 1];
			sccs = 0;

			Arrays.fill(parent, -1);
			Arrays.fill(found, -1);
			Arrays.fill(low_link, -1);
			Arrays.fill(in_stack, false);
			Arrays.fill(my_scc, -1);

			// STEP 2: visit all nodes
			timestamp = 0;
			for (int node = 1; node <= n; ++node) {
				if (parent[node] == -1) { // node not visited
					parent[node] = node; // convention: the parent of the root is actually the root

					// STEP 3: start a new DFS traversal this subtree
					dfs(node);
				}
			}
		}

		private void dfs(int node) {
			// STEP 1: a new node is visited - increment the timestamp
			found[node] = ++timestamp; // the timestamp when node was found
			low_link[node] = found[node]; // node only knows its timestamp
			nodes_stack.push(node); // add node to the visiting stack
			in_stack[node] = true;

			// STEP 2: visit each neighbour
			for (Integer neigh : adj[node]) {
				// STEP 3: check if neigh is already visited
				if (parent[neigh] != -1) {
					// STEP 3.1: update low_link[node] with information gained through neigh
					// note: neigh is in the same SCC with node only if it's in the visiting stack;
					// otherwise, neigh is from other SCC, so it should be ignored
					if (in_stack[neigh]) {
